solutions.cpp:
class Solution {
public:
    string solve(vector<string>& nums) {
        string result = "";
        for (int i = 0; i < nums.size(); i++) {
            if (i > 0) result += ' ' + nums[i];
        }
        if (!result.empty()) return result.substr(0, result.size() - 1);
        return result;
    }
};
